    .steps thead {
        display: none;
    }

    .steps > tbody > tr > td,
    .steps > tbody > tr > th {
        border-style: none !important;
    }

    .step--command,
    .step--purpose {
        display: table-row;
    }
}

figure img.scale {
    cursor: zoom-in;
    max-width: 100%;
}

figure img.scale.expanded {
    max-width: 98% !important;
    max-height: 98% !important;
