        opacity: 1;
    }
}

#search {
    display: flex;
    flex-direction: column;
    opacity: 0.75;
    height: calc(100% - 24px);
    flex: 0 0 300px;
    max-width: 300px;
    z-index: 1;
    transition: ease 0.5s;
}

#search.hidden {
    flex: 0 0 0px;
    transition: ease 0.5s;
}

#search.hidden #close-icon {
    opacity: 0;
}

#search-input {
    background-color: white;
    z-index: 1;
    position: absolute;
    right: 0;
    box-shadow: -1px 1px 4px 0px rgba(0, 0, 0, 0.1);
